import React from "react";

function App() {
  return (
    <div style={pageStyle}>

      {/* FORM CARD */}
      <div style={formCard}>

        <h2 style={{marginBottom:"20px"}}>💊 Log HCP Interaction</h2>

        <input placeholder="HCP Name" style={input}/>

        <select style={input}>
          <option>Interaction Type</option>
          <option>Meeting</option>
          <option>Call</option>
        </select>

        <input type="date" style={input}/>

        <textarea placeholder="Topics Discussed" style={input}></textarea>

        <select style={input}>
          <option>Doctor Sentiment</option>
          <option>Positive</option>
          <option>Neutral</option>
          <option>Negative</option>
        </select>

        <textarea placeholder="Follow-up Actions" style={input}></textarea>

        <button style={logButton}>Log Interaction</button>

      </div>


      {/* AI ASSISTANT */}
      <div style={aiCard}>

        <h3>🤖 AI Assistant</h3>

        <p style={{color:"#666"}}>
          Describe the meeting and AI will summarize & log the interaction.
        </p>

        <textarea
          placeholder="Example: Met Dr Sharma today. Discussed diabetes drug. Doctor showed interest."
          style={chatBox}
        />

        <button style={aiButton}>
          Ask AI
        </button>

      </div>

    </div>
  );
}


/* PAGE STYLE */

const pageStyle = {
  height:"100vh",
  display:"flex",
  justifyContent:"center",
  alignItems:"center",
  gap:"40px",
  background:"linear-gradient(135deg,#667eea,#764ba2)",
  fontFamily:"Arial"
};

/* FORM CARD */

const formCard = {
  width:"450px",
  padding:"30px",
  borderRadius:"15px",
  background:"rgba(255,255,255,0.95)",
  boxShadow:"0 15px 35px rgba(0,0,0,0.2)"
};

/* AI CARD */

const aiCard = {
  width:"350px",
  padding:"25px",
  borderRadius:"15px",
  background:"rgba(255,255,255,0.95)",
  boxShadow:"0 15px 35px rgba(0,0,0,0.2)"
};

/* INPUT */

const input = {
  width:"100%",
  padding:"10px",
  marginBottom:"15px",
  borderRadius:"8px",
  border:"1px solid #ddd",
  fontSize:"14px"
};

/* BUTTON */

const logButton = {
  width:"100%",
  padding:"12px",
  border:"none",
  borderRadius:"8px",
  background:"linear-gradient(90deg,#ff7e5f,#feb47b)",
  color:"white",
  fontSize:"16px",
  cursor:"pointer"
};

const aiButton = {
  width:"100%",
  padding:"12px",
  marginTop:"10px",
  border:"none",
  borderRadius:"8px",
  background:"linear-gradient(90deg,#36d1dc,#5b86e5)",
  color:"white",
  fontSize:"15px",
  cursor:"pointer"
};

/* CHAT */

const chatBox = {
  width:"100%",
  height:"120px",
  padding:"10px",
  borderRadius:"8px",
  border:"1px solid #ddd",
  marginTop:"10px"
};

export default App;
